function thermoPvClamp(n,s,l){return Math.max(s,Math.min(l,n))}
function thermoPvBuildPath(n,s,l){
  if(l==="orange"){
    const r=n.x+(s.x-n.x)*.34,c=n.y+10,m=n.x+(s.x-n.x)*.76,f=s.y-12;
    return `M ${n.x} ${n.y} C ${r} ${c}, ${m} ${f}, ${s.x} ${s.y}`
  }
  if(l==="grayDown"){
    const r=n.x+14,c=n.y+34,m=s.x-10,f=s.y-40;
    return `M ${n.x} ${n.y} C ${r} ${c}, ${m} ${f}, ${s.x} ${s.y}`
  }
  if(l==="green"){
    const r=n.x-(n.x-s.x)*.34,c=n.y-6,m=n.x-(n.x-s.x)*.76,f=s.y+6;
    return `M ${n.x} ${n.y} C ${r} ${c}, ${m} ${f}, ${s.x} ${s.y}`
  }
  const r=n.x-18,c=n.y-40,m=s.x-12,f=s.y+42;
  return `M ${n.x} ${n.y} C ${r} ${c}, ${m} ${f}, ${s.x} ${s.y}`
}
